#include<bits/stdc++.h>
using namespace std;
constexpr int mod=1e9+7;
long long l1,r1,ans;
int f[100010],g[100010],x[100010],y[100010],n,m;
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i>=1;i-=lowbit(i))
    {
        f[i]+=v;
        g[i]++;
    }
}
void query(int x)
{
    l1=r1=0;
    for(int i=x;i<=n;i+=lowbit(i))
    {
        l1+=f[i];
        r1+=g[i];
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
        query(x[i]);
        add(x[i],y[i]);
        ans+=l1+r1*y[i];
    }
    while(m--)
    {
        int l,r;
        scanf("%d%d",&l,&r);
        if(l>r)
        {
            swap(l,r);
        }
        int i=l+1;
        while(i<r)
        {
            if(x[i]>x[l])
            {
                ans+=y[i]+y[l];
            }
            if(x[i]<x[r])
            {
                ans+=y[i]+y[r];
            }
            if(x[i]<x[l])
            {
                ans-=y[i]+y[l];
            }
            if(x[i]>x[r])
            {
                ans-=y[i]+y[r];
            }
            i++;
        }
        if(x[l]>x[r])
        {
            ans-=y[l]+y[r];
        }
        if(x[l]<x[r])
        {
            ans+=y[l]+y[r];
        }
        swap(x[l],x[r]);
        swap(y[l],y[r]);
        ans=(ans%mod+mod)%mod;
        printf("%lld\n",ans);
    }
    return 0;
}
